const body = $input.item.json.body || {};
const courseName = body.courseName || 'Produção Audiovisual';
const studentName = body.studentName || 'Aluno TDS';
const certId = 'KRV-TDS-' + Math.random().toString(36).substring(2,8).toUpperCase();
const date = new Date().toLocaleDateString('pt-BR');

const html = `
<!DOCTYPE html><html><head><meta charset='utf-8'><style>
body{font-family:'Arial',sans-serif;text-align:center;padding:40px;border:10px solid #003366;margin:20px;background:#fcfcfc;} 
h1{color:#003366;font-size:3em;text-transform:uppercase;}
h2{color:#008080;} 
.info{font-size:1.5em;margin:30px 0;} 
.code{color:#555;font-size:1em;margin-top:50px;font-style:italic;} 
</style></head>
<body>
  <h1>Certificado de Conclusão</h1>
  <h2>Projeto Territórios de Desenvolvimento Social - IPEX</h2>
  <p class='info'>Certificamos que <strong>${studentName}</strong> concluiu com êxito o curso livre de <strong>${courseName}</strong> em ${date}.</p>
  <p class='info'>Aproveitamento: 100% | Carga Horária: 40h</p>
  <p class='code'>Código de Autenticidade: ${certId}</p>
</body></html>
`;

return [{ json: { html, certId } }];
